package com.jucheonsu.port.domain.user.service;
import com.jucheonsu.port.domain.common.enums.LanguageType;import com.jucheonsu.port.domain.user.dto.request.UserUpdateRequest;import com.jucheonsu.port.domain.user.entity.User;import com.jucheonsu.port.domain.user.repository.UserRepository;import com.jucheonsu.port.global.exception.CustomException;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.InjectMocks;import org.mockito.Mock;import org.mockito.junit.jupiter.MockitoExtension;import java.util.Optional;import static org.assertj.core.api.Assertions.*;import static org.mockito.BDDMockito.*;
@ExtendWith(MockitoExtension.class)class UserServiceImplTest{@Mock UserRepository userRepository;@InjectMocks UserServiceImpl service;@Test void getMe_success(){User user=User.builder().email("test@test.com").name("test").language(LanguageType.ko).build();given(userRepository.findByIdAndDeletedAtIsNull(1L)).willReturn(Optional.of(user));assertThat(service.getMe(1L).email()).isEqualTo("test@test.com");}@Test void getMe_notFound(){given(userRepository.findByIdAndDeletedAtIsNull(1L)).willReturn(Optional.empty());assertThatThrownBy(()->service.getMe(1L)).isInstanceOf(CustomException.class);}@Test void updateMe_success(){User user=User.builder().email("test@test.com").name("before").language(LanguageType.ko).build();given(userRepository.findByIdAndDeletedAtIsNull(1L)).willReturn(Optional.of(user));var res=service.updateMe(1L,new UserUpdateRequest("after","bio","Seoul",1,true));assertThat(res.name()).isEqualTo("after");}}
